  ('dietitian-moex-06643', 'dietitian', 'dietitian-moex-104-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '以母乳哺育嬰兒，下列有關鐵質的敘述何者正確？', '["母乳的鐵吸收率低於配方奶", "衛生福利部建議全面對4個月大的純母乳哺育寶寶補充鐵劑", "媽媽哺乳期的鐵攝取量是主要影響新生兒體內的鐵儲存量的因素", "衛生福利部建議對完全哺乳的早產兒或出生後有失血者，可提早補充鐵"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:44+00:00", "source_pdf_sha1": "94556ab0ca83", "answer_pdf_sha1": "7ff153154c45", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
